# Slack notification bot for new Anthropic changelog entries
# Run as a weekly cron job or GitHub Action

import hashlib, json, os, pathlib
import requests

WEBHOOK_URL = os.environ["SLACK_WEBHOOK_URL"]
CACHE_FILE = pathlib.Path(".anthropic_changelog_cache.json")

def fetch_changelog_page() -> str:
    """Fetch the changelog HTML from Anthropic docs."""
    # In practice, use the RSS feed if available, or scrape the known changelog URL
    # This is illustrative — check docs.anthropic.com/changelog for the actual format
    resp = requests.get("https://docs.anthropic.com/changelog", timeout=10)
    resp.raise_for_status()
    return resp.text

