    # ... parsing logic ...
    return entries

def load_cache() -> set[str]:
    if CACHE_FILE.exists():
        return set(json.loads(CACHE_FILE.read_text()))
    return set()

def save_cache(seen: set[str]) -> None:
    CACHE_FILE.write_text(json.dumps(list(seen)))

def post_to_slack(entry: dict) -> None:
    payload = {
        "text": f":anthropic: *New Changelog Entry*: {entry['title']}",
        "attachments": [{
            "color": "#ef4444" if "deprecat" in entry.get("title","").lower() else "#3b82f6",
            "text": entry.get("summary", ""),
            "footer": entry.get("date", ""),
        }]
    }
    requests.post(WEBHOOK_URL, json=payload)

def main():
    html = fetch_changelog_page()
    entries = extract_entries(html)
    seen = load_cache()
    new_entries = [e for e in entries if e["id"] not in seen]
    for entry in new_entries:
        post_to_slack(entry)
        seen.add(entry["id"])
    save_cache(seen)
    print(f"Posted {len(new_entries)} new entries")

if __name__ == "__main__":
    main()
